const messages = $input.all();
const BOT_ID = 'YOUR_DISCORD_BOT_ID';
const COOLDOWN_MS = 5 * 60 * 1000; // 5 minutes
const MAX_AGE_MS = 2 * 60 * 1000; // Ignorer les messages de plus de 2 minutes

const workflowStaticData = $getWorkflowStaticData('global');
const lastProcessedId = workflowStaticData.lastProcessedId || '0';
const lastProcessedTime = workflowStaticData.lastProcessedTime || 0;

// Prendre uniquement le dernier message
const message = messages[0];

if (!message || 
    !message.json.content || 
    !message.json.content.startsWith('/rr ') ||
    message.json.author?.id === BOT_ID) {
  return [];
}

// Vérifier l'age du message - ignorer si plus de 2 minutes
const messageTime = new Date(message.json.timestamp).getTime();
const now = Date.now();
if (now - messageTime > MAX_AGE_MS) {
  return [];
}

// Vérifier si ce message a déjà été traité
if (message.json.id === lastProcessedId) {
  return [];
}

// Vérifier le cooldown de 5 minutes
if (now - lastProcessedTime < COOLDOWN_MS) {
  return [];
}

// Sauvegarder l'ID et le timestamp
workflowStaticData.lastProcessedId = message.json.id;
workflowStaticData.lastProcessedTime = now;

// Parser le Riot ID
const riotId = message.json.content.replace('/rr ', '').trim();
if (!riotId.includes('#')) return [];

const [gameName, tagLine] = riotId.split('#');
return [{ json: { gameName, tagLine, apiKey: 'YOUR_RIOT_API_KEY' } }];

const ranks = $input.all().map(i => i.json);
const solo = ranks.find(r => r.queueType === 'RANKED_SOLO_5x5');
return [{ json: solo || { queueType: 'RANKED_SOLO_5x5', tier: 'UNRANKED' } }];

