const response = $input.first().json;
const coachingText = response.output || response.text || '';
const stats = $('Compute Global Stats').item.json;

return [{ json: { ...stats, coachingText } }];

const allItems = $input.all();

// Les parties sont dans la clé "games" du premier item qui en contient
let games = [];
let rankItems = [];

allItems.forEach(i => {
  if (i.json.games && Array.isArray(i.json.games)) {
    games = i.json.games;
  } else if (i.json.queueType !== undefined) {
    rankItems.push(i.json);
  } else if (i.json.champion !== undefined) {
    games.push(i.json);
  }
});

if (games.length === 0) {
  throw new Error(`Aucune partie trouvée. Items reçus: ${allItems.length}`);
}

// Rang Solo/Duo et Flex
const soloRank = rankItems.find(r => r.queueType === 'RANKED_SOLO_5x5') || null;
const flexRank = rankItems.find(r => r.queueType === 'RANKED_FLEX_SR') || null;

// Stats globales
const wins = games.filter(g => g.win).length;
const losses = games.length - wins;
const winrate = ((wins / games.length) * 100).toFixed(1);
const avgKills = (games.reduce((s, g) => s + g.kills, 0) / games.length).toFixed(1);
const avgDeaths = (games.reduce((s, g) => s + g.deaths, 0) / games.length).toFixed(1);
const avgAssists = (games.reduce((s, g) => s + g.assists, 0) / games.length).toFixed(1);
const avgKda = (games.reduce((s, g) => s + g.kda, 0) / games.length).toFixed(2);
const avgCs = (games.reduce((s, g) => s + parseFloat(g.csPerMin), 0) / games.length).toFixed(1);
const avgDmg = Math.round(games.reduce((s, g) => s + g.damageDealt, 0) / games.length);
const avgVision = (games.reduce((s, g) => s + g.visionScore, 0) / games.length).toFixed(1);
const avgKp = (games.reduce((s, g) => s + parseFloat(g.killParticipation), 0) / games.length).toFixed(0);

// Champions les plus joués
const champCount = {};
games.forEach(g => {
  champCount[g.champion] = (champCount[g.champion] || 0) + 1;
});
const topChamps = Object.entries(champCount)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 3)
  .map(([champ, count]) => {
    const champGames = games.filter(g => g.champion === champ);
    const champWins = champGames.filter(g => g.win).length;
    return `${champ} (${count} parties, ${((champWins/count)*100).toFixed(0)}% WR)`;
  });

// Série actuelle
let streak = 0;
let streakType = '';
for (let i = 0; i < games.length; i++) {
  if (i === 0) { streakType = games[i].win ? 'W' : 'L'; streak = 1; }
  else if ((games[i].win && streakType === 'W') || (!games[i].win && streakType === 'L')) { streak++; }
  else break;
}
const streakStr = `${streak} ${streakType === 'W' ? 'victoire(s)' : 'défaite(s)'} de suite`;

// Dernières 5 parties
const last5 = games.slice(0, 5).map(g =>
  `${g.win ? '✅' : '❌'} ${g.champion} | ${g.kills}/${g.deaths}/${g.assists} | ${g.position}`
).join('\n');


// Champion le plus joué (pour image dynamique)
const topChampName = Object.entries(champCount).sort((a, b) => b[1] - a[1])[0]?.[0] || 'Lux';
// Nettoyer le nom pour l'URL (ex: "Aurelion Sol" -> "AurelionSol")
const champNameForUrl = topChampName.replace(/[^a-zA-Z0-9]/g, '');
const championImageUrl = `https://ddragon.leagueoflegends.com/cdn/img/champion/splash/${champNameForUrl}_0.jpg`;

return [{
  json: {
    gameName: $('GET PUUID').item.json.gameName,
    tagLine: $('GET PUUID').item.json.tagLine,
    soloRank: soloRank ? `${soloRank.tier} ${soloRank.rank} - ${soloRank.leaguePoints} LP` : 'Non classé',
    soloWins: soloRank?.wins || 0,
    soloLosses: soloRank?.losses || 0,
    flexRank: flexRank ? `${flexRank.tier} ${flexRank.rank} - ${flexRank.leaguePoints} LP` : 'Non classé',
    totalGames: games.length,
    wins, losses, winrate,
    avgKills, avgDeaths, avgAssists, avgKda,
    avgCs, avgDmg, avgVision, avgKp,
    topChamps,
    streak: streakStr,
    last5,
    hotStreak: soloRank?.hotStreak || false,
    topChampName,
    championImageUrl
  }
}];

const puuid = $('GET PUUID').item.json.puuid;
const match = $input.item.json;
const participant = match.info.participants.find(p => p.puuid === puuid);

if (!participant) return {};

const durationMin = match.info.gameDuration / 60;

return {
  json: {
    matchId: match.metadata.matchId,
    champion: participant.championName,
    position: participant.teamPosition || participant.individualPosition,
    kills: participant.kills,
    deaths: participant.deaths,
    assists: participant.assists,
    kda: participant.deaths === 0 
      ? (participant.kills + participant.assists) 
      : ((participant.kills + participant.assists) / participant.deaths),
    win: participant.win,
    cs: participant.totalMinionsKilled + participant.neutralMinionsKilled,
    csPerMin: ((participant.totalMinionsKilled + participant.neutralMinionsKilled) / durationMin).toFixed(1),
    damageDealt: participant.totalDamageDealtToChampions,
    visionScore: participant.visionScore,
    killParticipation: (participant.challenges?.killParticipation * 100 || 0).toFixed(0),
    goldEarned: participant.goldEarned,
    durationMin: durationMin.toFixed(0),
    gameDate: new Date(match.info.gameEndTimestamp).toLocaleDateString('fr-FR')
  }
};

const allItems = $input.all();
const puuid = $('GET PUUID').item.json.puuid;

// Chaque item est un match ID dont les caractères sont splittés en clés
return allItems.map(item => {
  const chars = Object.values(item.json);
  const matchId = chars.join('');
  return { json: { matchId, puuid } };
});

// Extraire pseudo et tag depuis le body
const body = $input.first().json.body || $input.first().json;

let gameName, tagLine;

// Support format "ColoMiel#TDS" ou gameName + tagLine séparés
if (body.riotId && body.riotId.includes('#')) {
  [gameName, tagLine] = body.riotId.split('#');
} else if (body.gameName && body.gameName.includes('#')) {
  [gameName, tagLine] = body.gameName.split('#');
} else {
  gameName = body.gameName || 'ColoMiel';
  tagLine = body.tagLine || 'TDS';
}

const apiKey = body.apiKey || 'YOUR_RIOT_API_KEY';
return [{ json: { gameName, tagLine, apiKey } }];
